#include<iostream>
using namespace std;
int mv,mm,n,v[4001],m[4001],k[4001],dp[4001][4001];
int main()
{
	cin>>n>>mv>>mm;
	for(int i=1;i<=n;i++)  cin>>v[i]>>m[i]>>k[i];
	for(int i=1;i<=n;i++){
		for(int j=mv;j>=m[i];j--){
			for(int p=mm;p>=k[i];p--){
				dp[j][p]=max(dp[j][p],dp[j-m[i]][p-k[i]]+v[i]);
			}
		}
	}
	cout<<dp[mv][mm];
	return 0;
}
